css:
:host, .component-root {
  --m-blur: 40px;
  --m-saturate: 220%;
  --m-padding: 2rem;
  --m-gap: 1.5rem;
  --m-accent: #8b5cf6;
  --m-radius: 16px;
  font-family: Outfit;
}
.gen-card {
  max-width: 340px;
  background: #1a1f2e;
  border-radius: var(--m-radius);
  overflow: hidden;
  border: 1px solid rgba(255,255,255,0.06);
  transition: transform 0.2s ease, box-shadow 0.2s ease;
}
.gen-card:hover {
  transform: translateY(-4px);
  box-shadow: 0 12px 24px rgba(0,0,0,0.4);
}
.gen-card__image {
  height: 180px;
  background: linear-gradient(135deg, #6366f1, #06b6d4);
  position: relative;
}
.gen-card__badge {
  position: absolute;
  top: 12px;
  right: 12px;
  background: rgba(0,0,0,0.5);
  backdrop-filter: blur(var(--m-blur));
  padding: var(--m-padding);
  border-radius: var(--m-radius);
  font-size: 12px;
  color: #e0e7ff;
}
.gen-card__body { padding: var(--m-padding); }
.gen-card__title {
  font-size: 18px;
  font-weight: 600;
  color: #f1f5f9;
  margin-bottom: 8px;
}
.gen-card__desc {
  font-size: 14px;
  color: #94a3b8;
  line-height: 1.5;
  margin-bottom: 16px;
}
.gen-card__meta {
  display: flex;
  justify-content: space-between;
  align-items: center;
  margin-bottom: 16px;
}
.gen-card__price {
  font-size: 22px;
  font-weight: 700;
  color: #6366f1;
}
.gen-card__rating {
  font-size: 14px;
  color: #f59e0b;
}
.gen-card__btn {
  width: 100%;
  padding: var(--m-padding);
  background: #6366f1;
  color: white;
  border: none;
  border-radius: var(--m-radius);
  font-size: 14px;
  font-weight: 600;
  cursor: pointer;
  transition: background 0.2s;
}
.gen-card__btn:hover { background: #4f46e5; }

