css:
:host, .component-root {
  --m-blur: 40px;
  --m-saturate: 220%;
  --m-padding: 2rem;
  --m-gap: 1.5rem;
  --m-accent: #8b5cf6;
  --m-radius: 16px;
  font-family: Outfit;
}
.gen-dash {
  max-width: 700px;
  background: #1a1f2e;
  border-radius: var(--m-radius);
  padding: var(--m-padding);
  border: 1px solid rgba(255,255,255,0.06);
}
.gen-dash__header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  margin-bottom: 24px;
}
.gen-dash__header h2 {
  font-size: 20px;
  font-weight: 600;
  color: #f1f5f9;
}
.gen-dash__filter {
  background: #111827;
  color: #94a3b8;
  border: 1px solid rgba(255,255,255,0.1);
  padding: var(--m-padding);
  border-radius: var(--m-radius);
  font-size: 13px;
}
.gen-dash__grid {
  display: grid;
  grid-template-columns: repeat(4, 1fr);
  gap: var(--m-gap);
  margin-bottom: 24px;
}
.gen-dash__stat {
  background: #111827;
  border-radius: var(--m-radius);
  padding: var(--m-padding);
  border: 1px solid rgba(255,255,255,0.04);
}
.gen-dash__stat-label {
  display: block;
  font-size: 12px;
  color: #64748b;
  text-transform: uppercase;
  letter-spacing: 0.05em;
  margin-bottom: 4px;
}
.gen-dash__stat-value {
  display: block;
  font-size: 22px;
  font-weight: 700;
  color: #f1f5f9;
  margin-bottom: 4px;
}
.gen-dash__stat-change {
  font-size: 12px;
  font-weight: 600;
}
.gen-dash__stat-change.positive { color: #22c55e; }
.gen-dash__stat-change.negative { color: #ef4444; }
.gen-dash__chart {
  background: #111827;
  border-radius: var(--m-radius);
  padding: var(--m-padding);
  border: 1px solid rgba(255,255,255,0.04);
}
.gen-dash__chart-placeholder {
  display: flex;
  align-items: flex-end;
  gap: var(--m-gap);
  height: 120px;
}
.gen-dash__bar {
  flex: 1;
  background: linear-gradient(to top, #6366f1, #818cf8);
  border-radius: var(--m-radius);
  transition: height 0.5s ease;
}
.gen-dash__bar:hover {
  background: linear-gradient(to top, #4f46e5, #6366f1);
}

